    }
}

import com.sun.net.httpserver.HttpServer;
import java.io.IOException;
import java.io.InputStream;
import java.net.InetSocketAddress;
import java.nio.charset.StandardCharsets;

public class App {
    private static final Store store = new Store();

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/items", exchange -> {
            switch (exchange.getRequestMethod()) {
                case "GET" -> writeJson(exchange, 200, store.list().toString());
                case "POST" -> {
                    String body = new String(readAll(exchange.getRequestBody()), StandardCharsets.UTF_8);
                    String name = body.replaceAll(".*\"name\"\\s*:\\s*\"([^\"]+)\".*", "$1");
                    Item created = store.create(name);
                    writeJson(exchange, 201, created.toString());
                }
                default -> exchange.sendResponseHeaders(405, -1);
            }
        });
        server.start();
    }

    static byte[] readAll(InputStream in) throws IOException { return in.readAllBytes(); }

    static void writeJson(com.sun.net.httpserver.HttpExchange ex, int code, String json) throws IOException {
        byte[] body = json.getBytes(StandardCharsets.UTF_8);
        ex.getResponseHeaders().add("Content-Type", "application/json");
        ex.sendResponseHeaders(code, body.length);
        ex.getResponseBody().write(body);
        ex.close();
    }
}

public sealed interface Expr permits Num, Add {}

record Num(int value) implements Expr {}

record Add(Expr left, Expr right) implements Expr {}

public class Evaluator {
    public static int eval(Expr expr) {
        return switch (expr) {
            case Num(int v) -> v;
            case Add(var l, var r) -> eval(l) + eval(r);
        };
    }
}

public class Main {
