import java.util.concurrent.ArrayBlockingQueue;
import java.util.concurrent.BlockingQueue;

public class Pipeline {
    static void producer(BlockingQueue<String> q) throws InterruptedException {
        for (int i = 1; i <= 5; i++) q.put("job-" + i);
    }

    static void consumer(BlockingQueue<String> q) throws InterruptedException {
        for (int i = 0; i < 5; i++) {
            String item = q.take();
            System.out.println("consumed " + item);
        }
    }

    public static void main(String[] args) throws Exception {
        BlockingQueue<String> queue = new ArrayBlockingQueue<>(10);
        Thread p = new Thread(() -> run(producer(queue)));
        Thread c = new Thread(() -> run(consumer(queue)));
        p.start(); c.start();
        p.join(); c.join();
    }

    static void run(ThrowableRunnable r) { try { r.run(); } catch (InterruptedException e) { Thread.currentThread().interrupt(); } }
    @FunctionalInterface interface ThrowableRunnable { void run() throws InterruptedException; }
}

import java.util.concurrent.ArrayBlockingQueue;
import java.util.concurrent.BlockingQueue;

public class Pipeline {
    static final String POISON = "__STOP__";

    static void producer(BlockingQueue<String> q) throws InterruptedException {
        for (int i = 1; i <= 3; i++) q.put("job-" + i);
        q.put(POISON);
    }

    static void consumer(BlockingQueue<String> q) throws InterruptedException {
        while (true) {
            String item = q.take();
            if (POISON.equals(item)) break;
            System.out.println("consumed " + item);
        }
    }

    public static void main(String[] args) throws Exception {
        BlockingQueue<String> queue = new ArrayBlockingQueue<>(10);
        Thread p = new Thread(() -> run(() -> producer(queue)));
        Thread c = new Thread(() -> run(() -> consumer(queue)));
        p.start(); c.start();
        p.join(); c.join();
    }

    static void run(ThrowableRunnable r) { try { r.run(); } catch (InterruptedException e) { Thread.currentThread().interrupt(); } }
    @FunctionalInterface interface ThrowableRunnable { void run() throws InterruptedException; }
}
